LEVELS = {
    "Foundation": ["Financial Accounting","Management Information","Business Law","Quantitative Techniques in Business"],
    "Skills": ["Financial Reporting","Taxation","Performance Management","Audit and Assurance","Public Sector Accounting and Finance","Financial Management"],
    "Professional": ["Corporate Reporting","Advanced Taxation","Strategic Financial Management","Advanced Audit and Assurance","Case Study"],
}

def fmt(raw):
    labels = "ABCDE"
    return [{"text": raw[i][0], "is_correct": bool(raw[i][1]), "label": labels[i]} for i in range(len(raw))]

def main():
    conn = sqlite3.connect(DB)
    c = conn.cursor()
    total = 0

    for level, subjects in LEVELS.items():
        exam_name = f"ICAN {level}"
        c.execute("SELECT id FROM exams WHERE name=?", (exam_name,))
        r = c.fetchone()
        if r:
            eid = r[0]
        else:
            c.execute("INSERT INTO exams (name,category,description,sub_category) VALUES (?,?,?,?)",
                      (exam_name, "Professional", f"ICAN {level} Level Examination", level))
            eid = c.lastrowid

        for subj in subjects:
            c.execute("SELECT id FROM subjects WHERE name=? AND exam_id=?", (subj, eid))
            r = c.fetchone()
            if r:
                sid = r[0]
                c.execute("DELETE FROM choices WHERE question_id IN (SELECT id FROM questions WHERE subject_id=?)", (sid,))
                c.execute("DELETE FROM questions WHERE subject_id=?", (sid,))
            else:
                c.execute("INSERT INTO subjects (name,exam_id) VALUES (?,?)", (subj, eid))
                sid = c.lastrowid

            qs = ALL_DATA.get(subj, [])
            for q in qs:
                c.execute("INSERT INTO questions (subject_id,text,explanation,difficulty,year,is_ai_generated,section,topic) VALUES (?,?,?,?,?,?,?,?)",
                          (sid, q["t"], q.get("e",""), "MEDIUM", q.get("y",2024), False, "Multiple Choice", q.get("tp","")))
                qid = c.lastrowid
                for ch in fmt(q["c"]):
                    c.execute("INSERT INTO choices (question_id,text,is_correct,label) VALUES (?,?,?,?)",
                              (qid, ch["text"], ch["is_correct"], ch["label"]))
                total += 1
            print(f"  [{level}] {subj}: {len(qs)} questions (sid={sid})")

    conn.commit()
    conn.close()
    print(f"\n[DONE] {total} ICAN questions inserted across all 15 subjects.")

if __name__ == "__main__":
    main()
